{"code":"import json

with open(locals()['var_function-call-5679032680150065306'], 'r') as f:
    filenames = json.load(f)

# Regex for CHI: CHI followed by optional space, optional quote, optional space, 2-4 digits.
# Note: In JSON string, backslashes need to be escaped.
# In Python string literal for regex, we use raw string or escape.
# For JSON output, we need to ensure the string passed to MongoDB has correct regex.
# Regex: CHI\s*['\u2019]?\s*\d{2,4}
# Escaped for JSON: CHI\\s*['\\u2019]?\\s*\\d{2,4}

regex_chi = "CHI\\s*['\u2019]?\\s*\\d{2,4}"
regex_conf = "Conference on Human Factors"

query = {
    "collection": "paper_docs",
    "filter": {
        "filename": {"$in": filenames},
        "$or": [
            {"text": {"$regex": regex_chi, "$options": "i"}},
            {"text": {"$regex": regex_conf, "$options": "i"}}
        ]
    },
    "projection": {"filename": 1}
}

print("__RESULT__:")
print(json.dumps(query))"}
